/* Header click animation */
(function () {
  var header = document.querySelector('header');
  if (!header) return;

  var clickableSelector = 'a, button';

  header.addEventListener('click', function (event) {
    var target = event.target;
    if (!(target instanceof Element)) return;

    var clickable = target.closest(clickableSelector);
    if (!clickable || !header.contains(clickable)) return;

    if (clickable.tagName === 'A') {
      var href = clickable.getAttribute('href') || '';
      if (href.charAt(0) === '#' && href.length > 1) {
        var section = document.querySelector(href);
        if (section) {
          event.preventDefault();
          var headerHeight = header.getBoundingClientRect().height;
          var sectionTop =
            window.scrollY + section.getBoundingClientRect().top - headerHeight - 12;
          var prefersReducedMotion =
            window.matchMedia &&
            window.matchMedia('(prefers-reduced-motion: reduce)').matches;
          window.scrollTo({
            top: Math.max(0, sectionTop),
            behavior: prefersReducedMotion ? 'auto' : 'smooth',
          });
          if (window.history && window.history.pushState) {
            window.history.pushState(null, '', href);
          }
        }
      }
    }

    clickable.classList.remove('header-click-animate');
    // Force reflow so repeated fast clicks replay the animation
    void clickable.offsetWidth;
    clickable.classList.add('header-click-animate');
  });

  header.addEventListener('animationend', function (event) {
    var target = event.target;
    if (!(target instanceof Element)) return;
    target.classList.remove('header-click-animate');
  });
})();
